import ProjectHeader from "../components/projectPage/ProjectHeader";
import './ProjectPage.css';

const projectDict = {
  "clock": {
    "title": "Clock",
    "subtitle": "This is the clk subtitle",
    "metaLists": [
      { "title":"SKILLS",
        "items":["3dp","rhino","item3"],
      },
      { "title":"TOOLS",
        "items":["arduino","item2","item3"],
      },
    ],
    "content": <Cont_Clock></Cont_Clock>,
  },  

  "footwork": {
    "title": "Footwork XVII",
    "subtitle": "This is the fw subtitle",
    "metaLists": [
      { "title":"SKILLS",
        "items":["gd","3d","pub"],
      },
      { "title":"TOOLS",
        "items":["blender","item2","item3"],
      },
    ],
    "content": <Cont_Footwork></Cont_Footwork>,
  },
}



function Cont_Footwork({props}) {
  const project = "footwork"

  return (
    <div id="projectPage" className="content-left content-margintop content-padding">
      <ProjectHeader
        thumbSrc={"Footwork XVII"}
        title={"Footwork XVII"}
        subtitle={"This is the fw ssubt"}
        metaLists={[
          { "title":"SKILLS",
            "items":["gd","3d","pub"],
          },
          { "title":"TOOLS",
            "items":["blender","item2","item3"],
          },
        ]}
      ></ProjectHeader>

    </div>
  );
}

export default Cont_Footwork;
